from __future__ import annotations

import shutil
from pathlib import Path

from relocation_jobs.core.paths import PACKAGE_DIR, ensure_data_dir

ASSETS_DIR = PACKAGE_DIR / "mcp" / "assets"
MASTER_RESUME_NAME = "master_resume.tex"
PROFILE_NAME = "profile.json"
PROFILE_EXAMPLE_NAME = "profile.example.json"


def mcp_root() -> Path:
    return ensure_data_dir() / "mcp"


def master_resume_path() -> Path:
    return mcp_root() / MASTER_RESUME_NAME


def profile_path() -> Path:
    return mcp_root() / PROFILE_NAME


def applications_root() -> Path:
    return mcp_root() / "applications"


def application_dir(idempotency_key: str) -> Path:
    safe = (idempotency_key or "unknown").strip()
    if not safe:
        safe = "unknown"
    return applications_root() / safe


def tailored_tex_path(idempotency_key: str) -> Path:
    return application_dir(idempotency_key) / "resume.tex"


def pdf_path(idempotency_key: str) -> Path:
    return application_dir(idempotency_key) / "resume.pdf"


def application_meta_path(idempotency_key: str) -> Path:
    return application_dir(idempotency_key) / "meta.json"


def ensure_data_layout() -> Path:
    root = mcp_root()
    root.mkdir(parents=True, exist_ok=True)
    applications_root().mkdir(parents=True, exist_ok=True)
    master = master_resume_path()
    if not master.is_file():
        shutil.copy2(ASSETS_DIR / MASTER_RESUME_NAME, master)
    profile = profile_path()
    if not profile.is_file():
        shutil.copy2(ASSETS_DIR / PROFILE_EXAMPLE_NAME, profile)
    return root

from __future__ import annotations

import re

from relocation_jobs.mcp.types import ValidationIssue, ValidationResult

_YEAR_RE = re.compile(r"\b(19|20)\d{2}\b")
_EMPLOYER_LINE_RE = re.compile(
    r"\\textbf\{([^}]+)\}|\\company\{([^}]+)\}|\\position\{([^}]+)\}",
)
_MAX_LINES = 400


def _extract_years(text: str) -> set[str]:
    return set(_YEAR_RE.findall(text))


def _extract_employer_tokens(text: str) -> set[str]:
    tokens: set[str] = set()
    for match in _EMPLOYER_LINE_RE.finditer(text):
        for group in match.groups():
            if group:
                cleaned = group.strip()
                if len(cleaned) >= 3:
                    tokens.add(cleaned.lower())
    return tokens


def _structure_issues(tex: str) -> list[ValidationIssue]:
    issues: list[ValidationIssue] = []
    if "\\begin{document}" not in tex:
        issues.append(ValidationIssue(
            code="missing_document_begin",
            message="Missing \\begin{document}",
        ))
    if "\\end{document}" not in tex:
        issues.append(ValidationIssue(
            code="missing_document_end",
            message="Missing \\end{document}",
        ))
    begin_count = len(re.findall(r"\\begin\{", tex))
    end_count = len(re.findall(r"\\end\{", tex))
    if begin_count != end_count:
        issues.append(ValidationIssue(
            code="unbalanced_environments",
            message=f"Unbalanced \\begin/\\end ({begin_count} begins, {end_count} ends)",
        ))
    line_count = len(tex.splitlines())
    if line_count > _MAX_LINES:
        issues.append(ValidationIssue(
            code="too_long",
            message=f"Resume tex has {line_count} lines (max {_MAX_LINES})",
        ))
    return issues


def _fact_issues(tex: str, master_tex: str) -> list[ValidationIssue]:
    issues: list[ValidationIssue] = []
    master_years = _extract_years(master_tex)
    tailored_years = _extract_years(tex)
    extra_years = tailored_years - master_years
    if extra_years:
        issues.append(ValidationIssue(
            code="new_years",
            message=f"Years not in master resume: {', '.join(sorted(extra_years))}",
        ))

    master_employers = _extract_employer_tokens(master_tex)
    tailored_employers = _extract_employer_tokens(tex)
    extra_employers = tailored_employers - master_employers
    if extra_employers:
        issues.append(ValidationIssue(
            code="new_employers",
            message=f"Employer tokens not in master resume: {', '.join(sorted(extra_employers))}",
        ))
    return issues


def validate_tex_content(tex: str, master_tex: str) -> ValidationResult:
    issues = _structure_issues(tex) + _fact_issues(tex, master_tex)
    return ValidationResult(ok=not issues, issues=issues)

from __future__ import annotations

import os
import subprocess
from pathlib import Path

from relocation_jobs.mcp.types import RenderResult

_COMPILE_TIMEOUT_SEC = 60


def _latex_command() -> str:
    return (os.environ.get("MCP_LATEX_CMD") or "tectonic").strip() or "tectonic"


def _build_command(cmd: str, tex_path: Path, out_dir: Path) -> list[str]:
    name = Path(cmd).name
    if name == "tectonic":
        return [cmd, "--outdir", str(out_dir), str(tex_path)]
    if name in ("pdflatex", "xelatex", "lualatex"):
        return [cmd, "-interaction=nonstopmode", "-output-directory", str(out_dir), str(tex_path)]
    return [cmd, str(tex_path)]


def render_tex_to_pdf(tex_path: Path) -> RenderResult:
    if not tex_path.is_file():
        return RenderResult(ok=False, log=f"Tex file not found: {tex_path}")

    out_dir = tex_path.parent
    pdf_name = tex_path.with_suffix(".pdf").name
    cmd = _latex_command()
    argv = _build_command(cmd, tex_path, out_dir)

    try:
        completed = subprocess.run(
            argv,
            capture_output=True,
            text=True,
            timeout=_COMPILE_TIMEOUT_SEC,
            cwd=str(out_dir),
            check=False,
        )
    except FileNotFoundError:
        return RenderResult(
            ok=False,
            log=f"LaTeX compiler not found: {cmd}. Install tectonic or set MCP_LATEX_CMD.",
        )
    except subprocess.TimeoutExpired:
        return RenderResult(ok=False, log=f"LaTeX compile timed out after {_COMPILE_TIMEOUT_SEC}s")

    log = (completed.stdout or "") + (completed.stderr or "")
    pdf_path = out_dir / pdf_name
    if completed.returncode != 0 or not pdf_path.is_file():
        return RenderResult(ok=False, log=log.strip() or f"Compile failed (exit {completed.returncode})")

    return RenderResult(ok=True, pdf_path=str(pdf_path), log=log.strip())

from __future__ import annotations

import json

from mcp.server.fastmcp import FastMCP

from relocation_jobs.mcp import repo as mcp_repo
from relocation_jobs.mcp import service

mcp = FastMCP("relocation-jobs")


def _json(payload) -> str:
    if hasattr(payload, "model_dump"):
        return json.dumps(payload.model_dump(), indent=2)
    return json.dumps(payload, indent=2)


@mcp.tool()
def get_job_context(country: str, company: str, url: str) -> str:
    """Load job and tracking context for an application (title, ATS, flags, artifact paths)."""
    return _json(service.get_job_context(country, company, url))


@mcp.tool()
def list_application_queue(country: str = "") -> str:
    """List pinned and looking-to-apply jobs for the configured MCP user."""
    scope = country.strip() or None
    items = service.list_application_queue(country=scope)
    return _json([item.model_dump() for item in items])


@mcp.tool()
def get_master_resume() -> str:
    """Read the canonical master resume tex from data/mcp/master_resume.tex."""
    return mcp_repo.read_master_resume()


@mcp.tool()
def get_application_profile() -> str:
    """Read static application profile (name, email, LinkedIn, work authorization, …)."""
    return _json(mcp_repo.read_profile())


@mcp.tool()
def save_tailored_tex(country: str, company: str, url: str, content: str) -> str:
    """Save a tailored resume tex for this job under data/mcp/applications/<key>/."""
    return _json(service.save_tailored_tex_for_job(country, company, url, content))


@mcp.tool()
def validate_tex(country: str, company: str, url: str, tex_content: str = "") -> str:
    """Validate tailored tex against master resume (structure + fact checks)."""
    optional = tex_content.strip() or None
    return _json(service.validate_tailored_tex(country, company, url, tex_content=optional))


@mcp.tool()
def render_pdf(country: str, company: str, url: str) -> str:
    """Compile saved tailored tex to PDF using MCP_LATEX_CMD (default: tectonic)."""
    return _json(service.render_tailored_pdf(country, company, url))


@mcp.tool()
def mark_applied(country: str, company: str, url: str, applied: bool = True) -> str:
    """Mark the job applied (or unapplied) in the panel tracking DB."""
    return _json(service.mark_job_applied(country, company, url, applied=applied))


def main() -> None:
    mcp_repo.paths.ensure_data_layout()
    mcp.run()


if __name__ == "__main__":
    main()

